const leads = $input.all().map(i => i.json);
const total = leads.length;
const withEmail = leads.filter(l => l.email && l.email !== 'N/A').length;
const contacted = leads.filter(l => String(l.contactado).toUpperCase() === 'TRUE').length;
const replied = leads.filter(l => String(l.respondio).toUpperCase() === 'TRUE').length;
const byTier = {};
leads.forEach(l => { const t = l.tier || 'Sin tier'; if (!byTier[t]) byTier[t] = { total: 0, contacted: 0, withEmail: 0 }; byTier[t].total++; if (String(l.contactado).toUpperCase() === 'TRUE') byTier[t].contacted++; if (l.email && l.email !== 'N/A') byTier[t].withEmail++; });
const byNiche = {};
leads.forEach(l => { const n = l.niche || 'Sin nicho'; byNiche[n] = (byNiche[n] || 0) + 1; });
const tierLines = Object.entries(byTier).sort(([a],[b]) => a.localeCompare(b)).map(([t,d]) => `  • ${t}: ${d.total} total, ${d.withEmail} con email, ${d.contacted} contactados`).join('
');
const nicheLines = Object.entries(byNiche).sort(([,a],[,b]) => b - a).slice(0, 8).map(([n,c]) => `  • ${n}: ${c}`).join('
');
const pendientes = withEmail - contacted;
const text = `📊 *Estadísticas de Leads*

📋 *General:*
• Total: ${total}
• Con email: ${withEmail}
• Contactados: ${contacted}
• Respondieron: ${replied}
• *Pendientes: ${pendientes}*

📈 *Por Tier:*
${tierLines}

🏥 *Por Nicho (top):*
${nicheLines}`;
return [{ json: { textResponse: text, toolResponse: `${total} leads, ${withEmail} con email, ${contacted} contactados, ${pendientes} pendientes` }}];

const leads = $input.all().map(i => i.json);
const candidate = leads.find(l => { const email = l.email || ''; return email.includes('@') && email !== 'N/A' && String(l.contactado).toUpperCase() !== 'TRUE'; });
if (!candidate) { return [{ json: { textResponse: '📋 *Preview*

No hay leads pendientes para mostrar.', toolResponse: 'Sin leads pendientes' }}]; }
const reviews = parseInt(candidate.reviews_count) || 0;
const rating = parseFloat(candidate.rating) || 0;
const hasWeb = candidate.website && candidate.website.length > 10 && candidate.website !== 'N/A';
const hasIg = candidate.instagram && candidate.instagram.length > 5 && candidate.instagram !== 'N/A';
let angle = 'general';
if (reviews >= 50) angle = 'volume';
else if (hasIg) angle = 'social';
else if (hasWeb) angle = 'web';
const text = `📋 *Preview — Próximo Lead*

🏥 *${candidate.business_name}*
📍 ${candidate.city} | ${candidate.niche}
📧 ${candidate.email}
⭐ ${rating}★ — ${reviews} reseñas
🏷️ ${candidate.tier} | Score: ${candidate.score}
🌐 Web: ${hasWeb ? '✅' : '❌'} | IG: ${hasIg ? '✅' : '❌'}

🎯 *Ángulo:* ${angle}
📝 *Notas:* ${candidate.notas_investigacion || 'Sin notas'}
⭐ *Destacable:* ${candidate.datos_destacables || 'Nada'}

_El email se generará con IA al momento de enviar._`;
return [{ json: { textResponse: text, toolResponse: `Preview: ${candidate.business_name} (${candidate.tier}, ${reviews} reseñas, ángulo: ${angle})` }}];

let logs = [];
try { logs = $input.all().map(i => i.json); } catch(e) {}
if (logs.length === 0) { return [{ json: { textResponse: '📊 *Reporte de Outreach*\n\nNo hay correos enviados aún.', toolResponse: 'Sin correos enviados' }}]; }
const total = logs.length;
const sent = logs.filter(l => l.delivery_status === 'sent').length;
const failed = logs.filter(l => l.delivery_status === 'failed').length;
const replied = logs.filter(l => String(l.reply_detected).toLowerCase() === 'true').length;
const initial = logs.filter(l => (l.variant || '').startsWith('initial')).length;
const followup = total - initial;
const recent = logs.slice(-10).reverse();
const recentLines = recent.map(l => { const status = l.delivery_status === 'sent' ? '✅' : '❌'; const reply = String(l.reply_detected).toLowerCase() === 'true' ? ' 💬' : ''; const date = l.email_sent_date ? l.email_sent_date.split('T')[0] : '?'; return `  ${status}${reply} ${l.subject || '?'} — ${date}`; }).join('\n');
const successRate = total > 0 ? Math.round((sent / total) * 100) : 0;
const replyRate = sent > 0 ? Math.round((replied / sent) * 100) : 0;
const text = `📊 *Reporte de Outreach*\n\n📧 *Total:* ${total} correos\n✅ Enviados: ${sent} (${successRate}%)\n❌ Fallidos: ${failed}\n💬 Respondieron: ${replied} (${replyRate}%)\n📨 Iniciales: ${initial} | Follow-ups: ${followup}\n\n📋 *Últimos 10:*\n${recentLines}`;
return [{ json: { textResponse: text, toolResponse: `${total} correos, ${sent} exitosos (${successRate}%), ${replied} respuestas (${replyRate}%)` }}];

// ═══ SMART INPUT v2 — Extrae cantidad con regex, no LLM ═══
const staticData = $getWorkflowStaticData('global');
staticData.sentThisRun = [];
staticData.batch = [];

const input = $input.first().json;

const query = (
  input.query ||
  input.message ||
  input.text ||
  (input.message && input.message.text) ||
  ''
).trim();

const chatId = (
  input.chatId ||
  input.chat_id ||
  (input.message && input.message.chat && input.message.chat.id) ||
  ''
).toString();

// ✅ FIX CANTIDAD: Extraer con regex — determinista, no depende del LLM
// El Classifier a veces devuelve quantity:0 aunque el usuario dijo "2"
// causando effectiveMax = 50 (default) → se mandaban 50 correos
let direct_quantity = 0;
if (query) {
  const numMatch = query.match(/\b(\d+)\b/);
  if (numMatch) {
    const num = parseInt(numMatch[1]);
    if (num >= 1 && num <= 10000) direct_quantity = num;
  }
}

if (query) {
  return [{ json: { query, chatId, direct_quantity, _source: 'manual' } }];
} else {
  return [{ json: { query: 'envía outreach automático diario', chatId: '', direct_quantity: 0, _source: 'schedule' } }];
}

// ═══ 🔗 BRIDGE v2 — Con direct_quantity override ═══

const aiRaw = $input.first().json;
const trigger = $('When Executed by Another Workflow');
let chatId = '';
try { chatId = trigger.first().json.chatId || trigger.first().json.chat_id || ''; } catch(e) {}
try { if (!chatId) chatId = $('📦 Schedule Input').first().json.chatId || ''; } catch(e) {}

// ✅ FIX: Usar direct_quantity del regex como respaldo si el LLM falla
let direct_quantity = 0;
try { direct_quantity = parseInt($('📦 Schedule Input').first().json.direct_quantity) || 0; } catch(e) {}

let ai = {};
try {
  let text = aiRaw.output || aiRaw.text || '';
  if (typeof text === 'object' && text.action) { ai = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]);
  }
} catch(e) {
  ai = { action: 'send_outreach', quantity: 0 };
}

const llm_qty = parseInt(ai.quantity) || 0;
// LLM tiene prioridad; si devolvió 0, usar regex
const qty = llm_qty > 0 ? llm_qty : direct_quantity;
const effectiveMax = qty > 0 ? Math.min(qty, 10000) : 100;

return [{ json: {
  action: ai.action || 'send_outreach',
  quantity: qty,
  effective_max: effectiveMax,
  tier_filter: ai.tier_filter || '',
  niche_filter: ai.niche_filter || '',
  city_filter: ai.city_filter || '',
  only_followups: ai.only_followups || false,
  only_new: ai.only_new || false,
  intent_description: ai.intent_description || '',
  chatId: chatId,
  _qty_source: llm_qty > 0 ? 'llm' : (direct_quantity > 0 ? 'regex_override' : 'default_100'),
  config: {
    sheet_id: '1jRC7Gbs98sbyXQCCcglpM_MrQmFPwpQ3oYEo7C806QA',
    sender_name: 'Santiago Rubio',
    sender_title: 'CEO · Nexus',
    sender_phone: '+57 312 434 8669',
    photo_url: 'https://i.ibb.co/d42PT8j1/Dise-o-sin-t-tulo-6.jpg',
    whatsapp_link: 'https://wa.me/573124348669',
    max_emails_per_run: effectiveMax,
    max_followups: 3,
    followup_delay_days: 3,
    min_tier: 3
  }
}}];

const data = $('🔧 Filter Eligible').first().json;
const s = data._stats || {};
const bridge = $('🔗 Bridge').first().json;
const qty = bridge.quantity || 0;
const filters = [];
if (bridge.niche_filter) filters.push('nicho: ' + bridge.niche_filter);
if (bridge.city_filter) filters.push('ciudad: ' + bridge.city_filter);
if (bridge.tier_filter) filters.push('tier: ' + bridge.tier_filter);
const qtyNote = qty > 0 ? `\n📌 Pediste ${qty} pero no hay elegibles.` : '';
const filterNote = filters.length > 0 ? `\n🔍 Filtros: ${filters.join(', ')}` : '';
const text = `⚠️ *No hay leads elegibles*${qtyNote}${filterNote}\n\n📊 *Stats:*\n• Total en hoja: ${s.total || 0}\n• Sin email: ${s.noEmail || 0}\n• Email inválido: ${s.invalid || 0}\n• Tier filtrado: ${s.tierSkip || 0}\n` + (s.nicheSkip ? `• Nicho filtrado: ${s.nicheSkip}\n` : '') + (s.citySkip ? `• Ciudad filtrada: ${s.citySkip}\n` : '') + `• Ya completados: ${s.done || 0}`;
return [{ json: { textResponse: text, toolResponse: 'No hay leads elegibles' } }];

const items = $input.all();
const count = items.length;
const bridge = $('🔗 Bridge').first().json;
const qty = bridge.quantity || 0;
const filters = [];
if (bridge.niche_filter) filters.push('nicho: ' + bridge.niche_filter);
if (bridge.city_filter) filters.push('ciudad: ' + bridge.city_filter);
if (bridge.tier_filter) filters.push('tier: ' + bridge.tier_filter);
const filterLine = filters.length > 0 ? '\n🔍 Filtros: ' + filters.join(', ') : '';
const text = `📧 *Outreach iniciado*\n\n🔄 Procesando ${count} correos en segundo plano.${filterLine}\n⏱️ Te aviso cuando termine.`;
return [{ json: { textResponse: text, toolResponse: `Outreach: ${count} correos en proceso` }}];

let data = {};
try { data = $input.first().json; } catch(e) {}
const textResponse = data.textResponse || '📧 Outreach en proceso — te notifico cuando termine.';
const toolResponse = data.toolResponse || 'Outreach iniciado en segundo plano';
return [{ json: { textResponse, toolResponse } }];

const emailData = $('🎨 HTML Builder').first().json;
const sendResult = $('📧 Send Email').first().json;
const ok = !sendResult.error && (sendResult.id || sendResult.messageId);

return [{ json: {
  ...emailData,
  delivery_status: ok ? 'sent' : 'failed',
  delivery_error: sendResult.error || null,
  gmail_id: sendResult.id || sendResult.messageId || null
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.batch) staticData.batch = [];
const r = $input.first().json;
staticData.batch.push({ id: r.lead_id, biz: r.business_name, tier: r.tier, action: r.action_type, status: r.delivery_status });
return $input.all();

const staticData = $getWorkflowStaticData('global');
const batch = staticData.batch || [];
// LIMPIAR TODO al finalizar
staticData.batch = [];
staticData.sentThisRun = [];
staticData.emailsSentThisRun = [];

const bridge = $('🔗 Bridge').first().json;
const qty = bridge.quantity || 0;
const filters = [];
if (bridge.niche_filter) filters.push('nicho: ' + bridge.niche_filter);
if (bridge.city_filter) filters.push('ciudad: ' + bridge.city_filter);
if (bridge.tier_filter) filters.push('tier: ' + bridge.tier_filter);
if (bridge.only_followups) filters.push('solo followups');
if (bridge.only_new) filters.push('solo nuevos');
const sent = batch.filter(e => e.status === 'sent').length;
const failed = batch.filter(e => e.status === 'failed').length;
const skipped = batch.filter(e => e.status === 'skipped').length;
const initial = batch.filter(e => e.action === 'initial_contact').length;
const followup = batch.length - initial - skipped;
const byTier = {};
batch.filter(e => e.status !== 'skipped').forEach(e => { byTier[e.tier || '?'] = (byTier[e.tier || '?'] || 0) + 1; });
const tierLines = Object.entries(byTier).map(([t,c]) => `  • ${t}: ${c}`).join('\n');
const qtyLine = qty > 0 ? `\n📌 *Solicitados:* ${qty}` : '';
const filterLine = filters.length > 0 ? `\n🔍 *Filtros:* ${filters.join(', ')}` : '';
const skipLine = skipped > 0 ? `\n⏭️ Saltados (duplicados): ${skipped}` : '';
const text = `📧 *Outreach Completado*${qtyLine}${filterLine}\n\n✅ Enviados: ${sent}\n❌ Fallidos: ${failed}${skipLine}\n\n📊 *Por tipo:*\n  • Inicial: ${initial}\n  • Follow-up: ${followup}\n\n📋 *Por Tier:*\n${tierLines}`;
return [{ json: { textResponse: text, toolResponse: `Outreach: ${sent}/${qty > 0 ? qty : 'auto'} enviados` + (filters.length > 0 ? ' (' + filters.join(', ') + ')' : '') }}];

// ═══════════════════════════════════════════════════════════════════════════
// 🛡️ DEDUP CHECK MEJORADO - Verifica por LEAD_ID y por EMAIL
// ═══════════════════════════════════════════════════════════════════════════

const staticData = $getWorkflowStaticData('global');

// Inicializar arrays si no existen
if (!staticData.sentThisRun) staticData.sentThisRun = [];
if (!staticData.emailsSentThisRun) staticData.emailsSentThisRun = [];

const lead = $input.first().json;
const leadId = (lead.lead_id || '').toString().trim();
const email = (lead.email || '').toLowerCase().trim();

// Sin lead_id, dejarlo pasar con warning
if (!leadId) {
  lead._dedup_warning = 'no_lead_id';
  lead._skip = false;
  return [{ json: lead }];
}

// ═══ CHECK 1: Duplicado por lead_id ═══
if (staticData.sentThisRun.includes(leadId)) {
  return [{ json: { 
    _skip: true, 
    lead_id: leadId,
    email: email,
    _motivo: 'duplicado_lead_id_ya_enviado' 
  }}];
}

// ═══ CHECK 2: Duplicado por email ═══
if (email && staticData.emailsSentThisRun.includes(email)) {
  return [{ json: { 
    _skip: true, 
    lead_id: leadId,
    email: email,
    _motivo: 'duplicado_email_ya_enviado' 
  }}];
}

// ═══ PASAR: Registrar y continuar ═══
staticData.sentThisRun.push(leadId);
if (email) staticData.emailsSentThisRun.push(email);

lead._skip = false;
return [{ json: lead }];

const lead = $('❓ Skip?').first().json;
const reviews = parseInt(lead.reviews_count) || 0;
const rating = parseFloat(lead.rating) || 0;
let canMentionReviews = false, volumeLevel = 'none';
if (reviews >= 200) { canMentionReviews = true; volumeLevel = 'very_high'; } else if (reviews >= 50) { canMentionReviews = true; volumeLevel = 'high'; } else if (reviews >= 15) { volumeLevel = 'medium'; } else if (reviews >= 1) { volumeLevel = 'low'; }
let ratingInsight = '', canMentionRating = false;
if (rating >= 4.8) { ratingInsight = 'Calificación excelente'; canMentionRating = true; } else if (rating >= 4.5) { ratingInsight = 'Muy buena calificación'; canMentionRating = true; } else if (rating >= 4.0) { ratingInsight = 'Buena calificación'; } else { ratingInsight = 'Calificación normal'; }
const rawWeb = (lead.website || '').trim();
const rawIg = (lead.instagram || '').trim();
const hasWeb = rawWeb.length > 10 && rawWeb.toLowerCase() !== 'n/a';
const hasIg = rawIg.length > 5 && rawIg.toLowerCase() !== 'n/a';
const notes = (lead.notas_investigacion || '').trim();
const highlights = (lead.datos_destacables || '').trim();
const nicheMap = { 'Medicina Estética': { dolor: 'preguntas sobre precios de botox, hialurónico y disponibilidad', tipo: 'procedimientos' }, 'Odontología': { dolor: 'consultas sobre diseño de sonrisa, ortodoncia y precios', tipo: 'tratamientos dentales' }, 'Dermatología': { dolor: 'consultas repetitivas sobre tratamientos y costos', tipo: 'tratamientos de piel' }, 'Cirugía Plástica': { dolor: 'pacientes que piden mucha info antes de decidirse', tipo: 'cirugías' }, 'Oftalmología': { dolor: 'consultas sobre cirugía láser y disponibilidad', tipo: 'consultas' } };
const nicheInfo = nicheMap[lead.niche] || { dolor: 'consultas de pacientes por WhatsApp', tipo: 'servicios' };
const rawCity = (lead.city || '').trim();
const invalidCities = ['colombia','co','col','n/a','na','','null','undefined','otro','otros','nacional'];
const isValidCity = rawCity.length > 2 && !invalidCities.includes(rawCity.toLowerCase());
const city = isValidCity ? rawCity : '';
let bestAngle = 'general';
if (volumeLevel === 'very_high' || volumeLevel === 'high') bestAngle = 'volume';
else if (canMentionRating && rating >= 4.8) bestAngle = 'reputation';
else if (hasIg && volumeLevel !== 'none') bestAngle = 'social';
else if (hasWeb) bestAngle = 'web';
else if (volumeLevel === 'medium') bestAngle = 'growth';
const variant = Math.random() > 0.5 ? 'A' : 'B';
const bizName = (lead.business_name || '').trim();
let greeting = 'Hola, buenas tardes.', hasPersonName = false, extractedName = '';
const titlePatterns = [/^(Dra?\.?\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)/i,/^(Dr\.?\s+(?:[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+\s+)?([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+))/i];
const namePatterns = [/^([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+\s+(?:Medicina|Dermatolog|Odontolog|Clínica|Cirugía|Estética|Dental|Centro|Consult)/i,/^([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)\s+(?:Medicina|Dermatolog|Odontolog|Estética|Dental)/i];
const brandWords = ['clínica','clinica','centro','institute','instituto','dental','smile','sonrisa','odonto','dermo','skin','beauty','estudio','spa','laser','láser','corp','group','salud','medical','med ','the ','los ','las ','diseños','sonríe','sonrie','oral','face','body','alto','new','nova','premium','elite','top'];
const bizLower = bizName.toLowerCase();
const startsWithBrand = brandWords.some(w => bizLower.startsWith(w));
if (!startsWithBrand) { for (const pattern of titlePatterns) { const match = bizName.match(pattern); if (match) { let name = match[1].trim(); name = name.replace(/^Dr\s/i,'Dr. ').replace(/^Dra\s/i,'Dra. '); const parts = name.split(/\s+/); if (parts.length >= 3 && parts[0].match(/^Dra?\.?$/i)) { extractedName = parts[0].replace(/^Dr$/i,'Dr.').replace(/^Dra$/i,'Dra.') + ' ' + parts[parts.length-1]; } else { extractedName = name; } hasPersonName = true; break; } } if (!hasPersonName) { for (const pattern of namePatterns) { const match = bizName.match(pattern); if (match) { extractedName = match[1].trim().split(/\s+/)[0]; hasPersonName = true; break; } } } }
if (hasPersonName && extractedName) { greeting = 'Hola ' + extractedName + ', buenas tardes.'; }
return [{ json: { ...lead, _research: { business_name: bizName, city, has_valid_city: isValidCity, niche: lead.niche || 'salud', niche_dolor: nicheInfo.dolor, niche_tipo: nicheInfo.tipo, review_count: reviews, rating, can_mention_reviews: canMentionReviews, can_mention_rating: canMentionRating, rating_insight: ratingInsight, volume_level: volumeLevel, has_website: hasWeb, has_instagram: hasIg, notes, highlights, best_angle: bestAngle, tier: lead.tier || '', is_followup: lead._action === 'followup', followup_number: lead._followup_number || 0, greeting, has_person_name: hasPersonName, extracted_name: extractedName, ab_variant: variant } }}];

