if (!isFollowup) { const hook = variant === 'A' ? (ai.hook_A || '') : (ai.hook_B || ''); const pain = variant === 'A' ? (ai.pain_A || '') : (ai.pain_B || ''); subject = variant === 'A' ? (ai.subject_A || 'Pregunta rápida') : (ai.subject_B || '¿Agendan por WhatsApp?'); body = greeting + '

' + hook + '

' + pain + '

